type seasonCarModelThenLoader[Q orm.Loadable] struct {
	CarModel func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	Season   func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildSeasonCarModelThenLoader[Q orm.Loadable]() seasonCarModelThenLoader[Q] {
	type CarModelLoadInterface interface {
		LoadCarModel(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SeasonLoadInterface interface {
		LoadSeason(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return seasonCarModelThenLoader[Q]{
		CarModel: thenLoadBuilder[Q](
			"CarModel",
			func(ctx context.Context, exec bob.Executor, retrieved CarModelLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadCarModel(ctx, exec, mods...)
			},
		),
		Season: thenLoadBuilder[Q](
			"Season",
			func(ctx context.Context, exec bob.Executor, retrieved SeasonLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadSeason(ctx, exec, mods...)
			},
		),
	}
}

// LoadCarModel loads the seasonCarModel's CarModel into the .R struct
func (o *SeasonCarModel) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CarModel = nil
	o.R.Loaded.CarModel = false

	related, err := o.CarModel(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.SeasonCarModels = SeasonCarModelSlice{o}

	o.R.CarModel = related
	o.R.Loaded.CarModel = true
	return nil
}

// LoadCarModel loads the seasonCarModel's CarModel into the .R struct
func (os SeasonCarModelSlice) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carModels, err := os.CarModel(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.CarModel = nil
		o.R.Loaded.CarModel = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	seasonCarModelByKey := make(map[int32][]*SeasonCarModel, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		seasonCarModelByKey[o.CarModelID] = append(seasonCarModelByKey[o.CarModelID], o)
	}

	for _, rel := range carModels {

		owners, ok := seasonCarModelByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.CarModel != nil {
				continue
			}

			rel.R.SeasonCarModels = append(rel.R.SeasonCarModels, o)

			o.R.CarModel = rel

		}
	}

	return nil
}

