type seasonCarModelJoins[Q dialect.Joinable] struct {
	typ      string
	CarModel modAs[Q, carModelColumns]
	Season   modAs[Q, seasonColumns]
}

func (j seasonCarModelJoins[Q]) aliasedAs(alias string) seasonCarModelJoins[Q] {
	return buildSeasonCarModelJoins[Q](buildSeasonCarModelColumns(alias), j.typ)
}

func buildSeasonCarModelJoins[Q dialect.Joinable](cols seasonCarModelColumns, typ string) seasonCarModelJoins[Q] {
	return seasonCarModelJoins[Q]{
		typ: typ,
		CarModel: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelID),
					))
				}

				return mods
			},
		},
		Season: modAs[Q, seasonColumns]{
			c: Seasons.Columns,
			f: func(to seasonColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Seasons.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.SeasonID),
					))
				}

				return mods
			},
		},
	}
}
